import { IntrinsicException } from '@nestjs/common';

@Injectable()
export class UsersService {
  async findOrFail(id: string) {
    const user = await this.repo.findOne({ where: { id } });
    if (!user) {
      // control-flow error: don't pollute logs with a stack trace
      throw new IntrinsicException('User not found');
    }
    return user;
  }
}

@Get()
async find(
  @Query('from', new ParseDatePipe()) from: Date,
  @Query('to', new ParseDatePipe({ optional: true })) to?: Date,
) {
  return this.reports.between(from, to);
}

import { NestFactory } from '@nestjs/core';
import { AppModule } from './app.module';
import { ReportService } from './reports/report.service';

async function bootstrap() {
  const app = await NestFactory.createApplicationContext(AppModule);
  const reports = app.get(ReportService);
  await reports.generateDaily();
  await app.close();
}
bootstrap();

app.useGlobalPipes(
  new ValidationPipe({
    whitelist: true,            // strip properties not in the DTO
    forbidNonWhitelisted: true, // 400 if extra properties are sent
    transform: true,            // coerce payload into DTO instances
  }),
);
